const body = $input.first().json.body || $input.first().json;
const action   = body.action || '';
const chatId   = String(body.chatId || '');
const password = body.password || '';
const nom_boutique = body.nom_boutique || '';
const description  = body.description || null;
const telephone    = body.telephone || null;
const adresse      = body.adresse || null;
const nom     = body.nom || '';
const oldNom  = body.oldNom || '';
const newNom  = body.newNom || '';
const desc    = body.desc || null;
const cat     = body.cat || '';
const prix    = parseFloat(body.prix) || 0;
const taille  = body.taille || null;

function esc(v) {
  if (v === null || v === undefined || v === '') return 'NULL';
  return "'" + String(v).replace(/'/g, "''") + "'";
}

let sql = '';
let mode = action;

switch (action) {
  case 'get_profile':
    sql = `SELECT nom_boutique, description, telephone, adresse, statut FROM vendeurs WHERE telegram_chat_id = ${esc(chatId)} LIMIT 1`;
    break;
  case 'login':
    sql = `SELECT COUNT(*) AS cnt FROM vendeurs WHERE telegram_chat_id = ${esc(chatId)} AND password = ${esc(password)}`;
    break;
  case 'logout':
    sql = `UPDATE vendor_sessions SET step=NULL, authenticated=0 WHERE chat_id=${esc(chatId)}`;
    break;
  case 'register':
    sql = `INSERT IGNORE INTO vendeurs (telegram_chat_id, nom_boutique, description, telephone, adresse, password, statut) VALUES (${esc(chatId)}, ${esc(nom_boutique)}, ${esc(description)}, ${esc(telephone)}, ${esc(adresse)}, ${esc(password)}, 'en_attente')`;
    break;
  case 'list_categories':
    sql = `SELECT c.nom FROM categories_vendeur c JOIN vendeurs v ON v.id=c.vendeur_id WHERE v.telegram_chat_id=${esc(chatId)} ORDER BY c.nom`;
    break;
  case 'add_category':
    sql = `INSERT INTO categories_vendeur (vendeur_id, nom) SELECT id, ${esc(nom)} FROM vendeurs WHERE telegram_chat_id=${esc(chatId)} LIMIT 1`;
    break;
  case 'update_category':
    sql = `UPDATE categories_vendeur SET nom=${esc(newNom)} WHERE nom=${esc(oldNom)} AND vendeur_id=(SELECT id FROM vendeurs WHERE telegram_chat_id=${esc(chatId)} LIMIT 1)`;
    break;
  case 'delete_category':
    sql = `DELETE FROM categories_vendeur WHERE nom=${esc(nom)} AND vendeur_id=(SELECT id FROM vendeurs WHERE telegram_chat_id=${esc(chatId)} LIMIT 1)`;
    break;
  case 'list_products':
    sql = `SELECT p.nom, p.prix, p.description, p.taille FROM produits_vendeur p JOIN vendeurs v ON v.id=p.vendeur_id WHERE v.telegram_chat_id=${esc(chatId)} ORDER BY p.nom`;
    break;
  case 'add_product':
    sql = `INSERT INTO produits_vendeur (vendeur_id, categorie_id, nom, description, prix, taille) SELECT v.id, c.id, ${esc(nom)}, ${esc(desc)}, ${prix}, ${esc(taille)} FROM vendeurs v LEFT JOIN categories_vendeur c ON c.vendeur_id=v.id AND c.nom=${esc(cat)} WHERE v.telegram_chat_id=${esc(chatId)} LIMIT 1`;
    break;
  case 'update_product':
    sql = `UPDATE produits_vendeur SET nom=${esc(nom)}, description=${esc(desc)}, prix=${prix}, taille=${esc(taille)} WHERE nom=${esc(oldNom)} AND vendeur_id=(SELECT id FROM vendeurs WHERE telegram_chat_id=${esc(chatId)} LIMIT 1)`;
    break;
  case 'delete_product':
    sql = `DELETE FROM produits_vendeur WHERE nom=${esc(nom)} AND vendeur_id=(SELECT id FROM vendeurs WHERE telegram_chat_id=${esc(chatId)} LIMIT 1)`;
    break;
  default:
    return [{ json: { error: 'Action inconnue', action } }];
}

return [{ json: { action: mode, chatId, sql } }];

const action = $('Router Action TMA').first().json.action;
const rows   = $input.all().map(i => i.json);

switch (action) {
  case 'get_profile': {
    const d = rows[0];
    if (!d || !d.nom_boutique) return [{ json: { error: 'Non trouvé' } }];
    return [{ json: d }];
  }
  case 'login': {
    const cnt = parseInt(rows[0]?.cnt ?? 0);
    if (cnt > 0) {
      const chatId = $('Router Action TMA').first().json.chatId;
      return [{ json: { success: true, _saveSession: true, chatId } }];
    }
    return [{ json: { error: 'Mot de passe incorrect' } }];
  }
  case 'logout':
    return [{ json: { success: true } }];
  case 'register': {
    const affected = rows[0]?.affectedRows || 0;
    if (affected > 0) return [{ json: { success: true } }];
    return [{ json: { error: 'Déjà inscrit. Utilisez la connexion.' } }];
  }
  case 'list_categories':
    return [{ json: rows.filter(r => r && r.nom) }];
  case 'add_category':
  case 'add_product':
  case 'update_category':
  case 'update_product':
  case 'delete_category':
  case 'delete_product': {
    const aff = rows[0]?.affectedRows ?? 0;
    if (aff > 0) return [{ json: { success: true } }];
    return [{ json: { error: 'Opération échouée. Vérifiez que vous êtes connecté.' } }];
  }
  case 'list_products':
    return [{ json: rows.filter(r => r && r.nom) }];
  default:
    return [{ json: { error: 'Action non gérée' } }];
}
